n_qubits = 180

# Convert stabilizer strings to PauliString objects
pauli_strings = [stim.PauliString(s) for s in stabilizers]

# Use Stim's tableau synthesis
tab = stim.Tableau.from_stabilizers(pauli_strings, allow_redundant=True, allow_underconstrained=True)
circuit = tab.to_circuit(method='graph_state')

# Convert RX to H (since we start from |0>)
lines = []
for inst in circuit:
    name = inst.name
    if name == 'RX':
        for t in inst.targets_copy():
            lines.append(f"H {t.value}")
    else:
        targets = ' '.join(str(t.value) for t in inst.targets_copy())
        lines.append(f"{name} {targets}")

circuit_str = '\n'.join(lines)
print(circuit_str)
print("---")
print(f"Circuit has {len(lines)} instructions")
